compliant:
public class MyClass
{
    private List<string> items = new List<string>();

    public IReadOnlyList<string> Items
    {
        get { return items; } // Compliant - no copy
    }

    public List<string> GetItemsCopy()
    {
        return items.ToList(); // Compliant - method clearly indicates copy
    }

    public string[] GetItemsArray()
    {
        return items.ToArray(); // Compliant - method clearly indicates copy
    }
}
